var data = $input.first().json;
var hookPrompt = data.hook_prompt_video || 'mysterious dark figure in shadows, dramatic lighting, cinematic, vertical 9:16, no text, no words';
// Sanitize prompt - no explicit religious words that could be blocked
hookPrompt = hookPrompt.replace(/\b(jesus|christ|god|deus|bible|biblia|cross|cruz)\b/gi, '').trim();
if (!hookPrompt) hookPrompt = 'mysterious shadowy figure engulfed in dark smoke and flames, dramatic moody cinematic lighting, vertical 9:16';

return [{ json: { ...data, hookPrompt: hookPrompt } }];

var data = $input.first().json;
var opName = data._veo2OpName;
if (!opName) throw new Error('No _veo2OpName in data');

var https2 = require('https');
function httpGet(url) {
  return new Promise(function(resolve, reject) {
    https2.get(url, { rejectUnauthorized: false }, function(res) {
      var buf = '';
      res.on('data', function(d) { buf += d; });
      res.on('end', function() {
        try { resolve(JSON.parse(buf)); } catch(e) { reject(e); }
      });
    }).on('error', reject);
  });
}

var pollUrl = 'https://generativelanguage.googleapis.com/v1beta/' + opName + '?key=' + data.GOOGLE_AI_API_KEY;
var resp = await httpGet(pollUrl);
if (resp.done) {
  return [{ json: { ...resp, ...data } }];
} else {
  // Not done yet — return a signal to keep waiting
  return [{ json: { ...data, _veo2Done: false, _veo2Resp: resp } }];
}

const childProcess = require('child_process');
const fs = require('fs');
const https = require('https');
const http = require('http');
const path = require('path');

// 1. Captura os dados de entrada
const inputData = $input.first().json;
const videoId = inputData.videoId || 'PI_' + Date.now();
const apiKey = inputData.GOOGLE_AI_API_KEY;

// 2. Define e cria o diretório temporário
const tempDir = '/home/node/.n8n/temp/' + videoId;
if (!fs.existsSync(tempDir)) {
  fs.mkdirSync(tempDir, { recursive: true });
}

// Função de Download com suporte a Redirect e API Key
function downloadFile(fileUrl, destPath, key) {
  return new Promise((resolve, reject) => {
    const protocol = fileUrl.startsWith('https:') ? https : http;
    const file = fs.createWriteStream(destPath);

    // Configura headers para evitar 403 (Proibido)
    const options = {
      rejectUnauthorized: false,
      headers: {
        'x-goog-api-key': key
      }
    };

    protocol.get(fileUrl, options, (res) => {
      // Trata Redirecionamentos (301, 302)
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        file.close();
        fs.unlinkSync(destPath);
        return downloadFile(res.headers.location, destPath, key).then(resolve).catch(reject);
      }

      if (res.statusCode !== 200) {
        reject(new Error(`Falha no download: Status ${res.statusCode}`));
        return;
      }

      res.pipe(file);
      file.on('finish', () => {
        file.close(resolve);
      });
    }).on('error', (err) => {
      fs.unlink(destPath, () => {});
      reject(err);
    });
  });
}

// 3. Extração da URI do Veo 2.0 (Caminho exato do seu input)
let videoUri = null;
try {
  // O caminho no seu JSON é: response.generateVideoResponse.generatedSamples[0].video.uri
  if (inputData.response && inputData.response.generateVideoResponse) {
    const samples = inputData.response.generateVideoResponse.generatedSamples;
    if (samples && samples.length > 0) {
      videoUri = samples[0].video.uri;
    }
  }
} catch (e) {
  console.log("Erro ao mapear estrutura do Veo2: " + e.message);
}

if (!videoUri) {
  throw new Error('URI do vídeo não encontrada. Verifique se o Veo2 completou a geração.');
}

// 4. Processamento de Download e FFmpeg
const rawHook = path.join(tempDir, 'hook_raw.mp4');
const hookFile = path.join(tempDir, 'hook.mp4');

try {
  // Download do vídeo original
  await downloadFile(videoUri, rawHook, apiKey);

  // FFmpeg: Corta 4s, remove áudio (-an) e força 9:16 (1080x1920) com Crop inteligente
  // Isso evita que o vídeo fique "esticado" ou "esmagado"
  childProcess.execSync(
    `ffmpeg -y -i "${rawHook}" ` +
    `-t 4 -c:v libx264 -preset veryfast -crf 23 ` +
    `-vf "scale=1080:1920:force_original_aspect_ratio=increase,crop=1080:1920,setsar=1" -an ` +
    `"${hookFile}"`,
    { timeout: 120000 }
  );

  // 5. Lê o arquivo final e retorna como binário para o n8n
  const fileBuffer = fs.readFileSync(hookFile);

  return [{
    json: { 
      ...inputData, 
      hookLocalPath: hookFile,
      status: 'hook_processed'
    },
    binary: {
      data: {
        data: fileBuffer.toString('base64'),
        mimeType: 'video/mp4',
        fileName: `${videoId}_hook.mp4`,
        fileExtension: 'mp4'
      }
    }
  }];

} catch (err) {
  throw new Error(`Erro no processamento do vídeo: ${err.message}`);
}

var data = $input.first().json;

// AQUI ESTÁ A MÁGICA: Puxando do nó de Upload em vez do nó de Share!
// ATENÇÃO: Substitua 'Drive: Upload Hook' pelo nome EXATO do seu nó verdinho que fez o upload do vídeo.
var driveUpload = $('Drive: Upload Hook').first().json; 

var hookVideoUrl = 'https://drive.google.com/uc?export=download&id=' + driveUpload.id;

return [{
  json: {
    ...data,
    hookVideoUrl: hookVideoUrl,
    hookDriveId: driveUpload.id,
    hookReady: true
  }
}];

